// MARK: - KeychainService
final class KeychainService {
    static let shared = KeychainService()
    private init() {}

    func save(_ key: String, data: Data) -> Bool {
        let query: [String: Any] = [
            kSecClass             as String: kSecClassGenericPassword,
            kSecAttrAccount       as String: key,
            kSecValueData         as String: data,
            kSecAttrAccessible    as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemDelete(query as CFDictionary)
        return SecItemAdd(query as CFDictionary, nil) == errSecSuccess
    }

    func load(_ key: String) -> Data? {
        let query: [String: Any] = [
            kSecClass              as String: kSecClassGenericPassword,
            kSecAttrAccount        as String: key,
            kSecReturnData         as String: true,
            kSecMatchLimit         as String: kSecMatchLimitOne
        ]
        var dataTypeRef: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &dataTypeRef)
        guard status == errSecSuccess else { return nil }
        return dataTypeRef as? Data
    }

    func delete(_ key: String) {
        let query: [String: Any] = [
            kSecClass        as String: kSecClassGenericPassword,
            kSecAttrAccount  as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - WalletManager
final class WalletManager {
    static let shared = WalletManager()
    private let keychainKey = "wallet_keystore"
    private init() {}

    private var keystore: EthereumKeystoreV3? {
        if let data = KeychainService.shared.load(keychainKey) {
            return try? EthereumKeystoreV3(data)
        }
        return nil
    }

    var address: EthereumAddress? {
        keystore?.addresses?.first
    }

    func walletExists() -> Bool {
        keystore != nil
    }

    @discardableResult
    func createWallet(password: String) throws -> EthereumAddress {
        let keystore = try EthereumKeystoreV3(password: password)!
        let data = try JSONEncoder().encode(keystore.keystoreParams)
        guard KeychainService.shared.save(keychainKey, data: data) else {
            throw NSError(domain: "KeychainError", code: -1, userInfo: nil)
        }
        return keystore.addresses!.first!
    }

    func importWallet(json: String, password: String) throws -> EthereumAddress {
        guard let data = json.data(using: .utf8) else {
            throw NSError(domain: "ImportError", code: -1, userInfo: nil)
        }
        guard let ks = EthereumKeystoreV3(json) else {
            throw NSError(domain: "ImportError", code: -2, userInfo: nil)
        }
        _ = try ks.UNSAFE_getPrivateKeyData(password: password, account: ks.addresses!.first!)
        guard KeychainService.shared.save(keychainKey, data: data) else {
            throw NSError(domain: "KeychainError", code: -1, userInfo: nil)
        }
        return ks.addresses!.first!
    }

    func exportKeystore() throws -> String {
        guard
            let data = KeychainService.shared.load(keychainKey),
            let json = String(data: data, encoding: .utf8)
        else {
            throw NSError(domain: "ExportError", code: -1, userInfo: nil)
        }
        return json
    }

    func sign(transaction: EthereumTransaction, password: String) throws -> Data {
        guard let ks = keystore else {
            throw NSError(domain: "SignError", code: -1, userInfo: nil)
        }
        var tx = transaction
        try Web3Signer.signTX(transaction: &tx, keystore: ks, account: address!, password: password)
        guard let data = tx.encode() else {
            throw NSError(domain: "SignError", code: -2, userInfo: nil)
        }
        return data
    }
}

// MARK: - BlockchainService
final class BlockchainService {
    static let shared = BlockchainService()
    private let web3: web3
    private init() {
        let rpcURL = URL(string: "https://mainnet.infura.io/v3/YOUR-PROJECT-ID")!
        let provider = Web3HttpProvider(rpcURL)!
        web3 = web3(provider: provider)
    }

    func getBalance(address: EthereumAddress) async throws -> BigUInt {
        try await withCheckedThrowingContinuation { cont in
            web3.eth.getBalance(address: address) { res in
                switch res {
                case .success(let bal): cont.resume(returning: bal)
                case .failure(let err): cont.resume(throwing: err)
                }
            }
        }
    }

    func sendRawTransaction(_ data: Data) async throws -> String {
        try await withCheckedThrowingContinuation { cont in
            web3.eth.sendRawTransaction(data) { res in
                switch res {
                case .success(let hash): cont.resume(returning: hash)
                case .failure(let err):  cont.resume(throwing: err)
                }
            }
        }
    }
}

// MARK: - ViewModel
@MainActor
final class WalletViewModel: ObservableObject {
    @Published var address: String = "No wallet"
    @Published var balance: String = "--"
    @Published var errorMessage: String?

    func createNewWallet(password: String) {
        do {
            let addr = try WalletManager.shared.createWallet(password: password)
            address = addr.address
            fetchBalance()
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func importWallet(json: String, password: String) {
        do {
            let addr = try WalletManager.shared.importWallet(json: json, password: password)
            address = addr.address
            fetchBalance()
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func fetchBalance() {
        guard let ethAddress = WalletManager.shared.address else { return }
        Task {
            do {
                let bal = try await BlockchainService.shared.getBalance(address: ethAddress)
                balance = Web3.Utils.formatToEthereumUnits(bal, toUnits: .eth, decimals: 4)!
            } catch {
                errorMessage = error.localizedDescription
            }
        }
    }

    func sendEther(to: String, amount: Double, gasPriceGwei: Double, password: String) {
        guard
            let fromAddress = WalletManager.shared.address,
            let toAddress   = EthereumAddress(to)
        else { return }

        Task {
            do {
                let gasPrice = Web3.Utils.parseToBigUInt(String(gasPriceGwei), units: .Gwei)!
                let value = Web3.Utils.parseToBigUInt(String(amount), units: .eth)!
                let nonce = try await BlockchainService.shared.web3.eth.getTransactionCount(address: fromAddress)
                let tx = EthereumTransaction(
                    nonce: nonce,
                    gasPrice: gasPrice,
                    gasLimit: BigUInt(21000),
                    to: toAddress,
                    value: value,
                    data: Data()
                )
                let signed = try WalletManager.shared.sign(transaction: tx, password: password)
                let txHash = try await BlockchainService.shared.sendRawTransaction(signed)
                print("TX Hash: \(txHash)")
                fetchBalance()
            } catch {
                errorMessage = error.localizedDescription
            }
        }
    }
}

// MARK: - SwiftUI Views
struct ContentView: View {
    @EnvironmentObject var vm: WalletViewModel
    @State private var password = ""
    @State private var toAddress = ""
    @State private var amount = ""
    @State private var gasPrice = "20"

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text("Wallet")) {
                    Text("Address: \(vm.address)")
                    Text("Balance: \(vm.balance) ETH")
                    SecureField("Password", text: $password)
                    Button("Create Wallet") {
                        vm.createNewWallet(password: password)
                    }
                }

                Section(header: Text("Send Ether")) {
                    TextField("Recipient", text: $toAddress)
                    TextField("Amount (ETH)", text: $amount)
                    TextField("Gas Price (Gwei)", text: $gasPrice)
                    SecureField("Wallet Password", text: $password)
                    Button("Send") {
                        if let amt = Double(amount), let gas = Double(gasPrice) {
                            vm.sendEther(to: toAddress, amount: amt, gasPriceGwei: gas, password: password)
                        }
                    }
                }

                if let err = vm.errorMessage {
                    Section {
                        Text(err).foregroundColor(.red)
                    }
                }
            }
            .navigationTitle("Crypto Wallet MVP")
        }
    }
}

// MARK: - App Entry
@main
struct WalletApp: App {
    @StateObject private var vm = WalletViewModel()
    var body: some Scene {
        WindowGroup {
            ContentView().environmentObject(vm)
        }
    }
